/**
 * NAV BRAND BAR
 * Thin top-of-page identity strip matching the design system.
 * Reference: rafeeq-design-system preview/brand-logo.html and the
 * UI kit Toolbar component's no-back-button variant.
 *
 * Layout:
 *   ┌──────────────────────────────────────────────────────┐
 *   │  رفيق · RAFEEQ                              [icon]   │
 *   └──────────────────────────────────────────────────────┘
 *
 * Use this on entry-style pages (QuizList, Azkar list, Settings).
 * Pages with their own back-button toolbar (Mushaf reader, quiz tests)
 * should NOT render this — their toolbar already handles identity.
 */

import React from "react";
import { useLang } from "../../../core/context/LanguageContext";
import "./NavBrandBar.css";

interface Props {
  /** Optional title shown to the right of the brand. */
  title?: string;
  /** When true, pin to the top of the nearest positioned ancestor. */
  fixed?: boolean;
}

const NavBrandBar: React.FC<Props> = ({ title, fixed }) => {
  const { t } = useLang();

  return (
    <header
      className={"rfq-brand-bar" + (fixed ? " rfq-brand-bar-fixed" : "")}
      role="banner"
      aria-label={t.appName}
    >
      <div className="rfq-brand-stack">
        <span className="rfq-brand-ar">{t.appName}</span>
        <span className="rfq-brand-sep" aria-hidden="true">·</span>
        <span className="rfq-brand-en">RAFEEQ</span>
      </div>

      {title && <span className="rfq-brand-title">{title}</span>}
    </header>
  );
};

export default NavBrandBar;
